mapper.select:
SELECT id, user_id, token_hash, expires_at, used_at
FROM password_reset_tokens
WHERE token_hash = #{tokenHash}

mapper.update:
UPDATE password_reset_tokens
SET used_at = #{usedAt}
WHERE id = #{id}
  AND used_at IS NULL

UPDATE password_reset_tokens
SET used_at = #{usedAt}
WHERE user_id = #{userId}
  AND used_at IS NULL
